use std::collections::HashSet;

fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let total_mask = 1 << n;

    if n == 0 {
        return 0;
    }

    let mut masks_by_pop = vec![vec![]; n + 1];
    for mask in 0..total_mask {
        let cnt = mask.count_ones() as usize;
        masks_by_pop[cnt].push(mask);
    }

    let mut and_mask = vec![0; total_mask];
    let mut xor_mask = vec![0; total_mask];

    and_mask[0] = 0;
    xor_mask[0] = 0;
    for cnt in 1..=n {
        for &mask in &masks_by_pop[cnt] {
            let j0 = mask.trailing_zeros() as usize;
            let mask_prev = mask ^ (1 << j0);
            and_mask[mask] = if cnt == 1 {
                nums[j0]
            } else {
                and_mask[mask_prev] & nums[j0]
            };
            xor_mask[mask] = xor_mask[mask_prev] ^ nums[j0];
        }
    }

    let total_xor = xor_mask[total_mask - 1];

    let mut set_table = vec![None; total_mask];
    set_table[0] = Some(HashSet::from([0]));
    let mut F = vec![0; total_mask];
    F[0] = 0;

    for k in 1..=n {
        for &mask in &masks_by_pop[k] {
            let j0 = mask.trailing_zeros() as usize;
            let mask_prev = mask ^ (1 << j0);
            if let Some(prev_set) = set_table[mask_prev].as_ref() {
                let mut new_set = HashSet::with_capacity(prev_set.len() * 2);
                for &x in prev_set.iter() {
                    new_set.insert(x);
                    new_set.insert(x ^ nums[j0]);
                }
                set_table[mask] = Some(new_set);
                let t = xor_mask[mask];
                let mut best = 0;
                for &x in set_table[mask].as_ref().unwrap() {
                    let val = x + (t ^ x);
                    if val > best {
                        best = val;
                    }
                }
                F[mask] = best;
            } else {
                panic!("Parent set not found");
            }
        }
        if k - 1 >= 0 {
            for &mask_prev in &masks_by_pop[k - 1] {
                set_table[mask_prev] = None;
            }
        }
    }

    let mut ans = 0;
    for mask_b in 0..total_mask {
        let mask_r = (total_mask - 1) ^ mask_b;
        let total_value = and_mask[mask_b] + F[mask_r];
        if total_value > ans {
            ans = total_value;
        }
    }
    ans
}
